   685→// Get practice statistics
   686→router.get('/practice/stats', authMiddleware, async (req, res) => {
   687→  try {
   688→    const stats = await pool.query(
   689→      `SELECT
   690→        COUNT(*) as total_questions,
   691→        AVG(score) as average_score,
   692→        MAX(created_at) as last_practice
   693→       FROM practice_sessions
   694→       WHERE user_id = $1`,
   695→      [req.user.id]
   696→    );
   697→
   698→    // Calculate improvement (compare first half vs second half of sessions)
   699→    const improvement = await pool.query(
   700→      `WITH ordered_sessions AS (
   701→        SELECT score, ROW_NUMBER() OVER (ORDER BY created_at) as rn,
   702→               COUNT(*) OVER () as total
   703→        FROM practice_sessions
   704→        WHERE user_id = $1
   705→      )
   706→      SELECT
   707→        AVG(CASE WHEN rn <= total/2 THEN score END) as first_half_avg,
   708→        AVG(CASE WHEN rn > total/2 THEN score END) as second_half_avg
   709→      FROM ordered_sessions`,
   710→      [req.user.id]
   711→    );
   712→
   713→    let improvementPercent = null;
   714→    if (improvement.rows[0].first_half_avg && improvement.rows[0].second_half_avg) {
   715→      const firstHalf = parseFloat(improvement.rows[0].first_half_avg);
   716→      const secondHalf = parseFloat(improvement.rows[0].second_half_avg);
   717→      improvementPercent = ((secondHalf - firstHalf) / firstHalf) * 100;
   718→    }
   719→
   720→    // Calculate day streak
   721→    const streakResult = await pool.query(
   722→      `WITH RECURSIVE date_series AS (
   723→        SELECT CURRENT_DATE::date as check_date, 0 as days_back
   724→        UNION ALL
   725→        SELECT (check_date - INTERVAL '1 day')::date, days_back + 1
   726→        FROM date_series
   727→        WHERE days_back < 30
   728→      )
   729→      SELECT COUNT(*) as streak
   730→      FROM date_series d
   731→      WHERE EXISTS (
   732→        SELECT 1 FROM practice_sessions
   733→        WHERE user_id = $1 AND DATE(created_at) = d.check_date
   734→      )
   735→      AND d.check_date <= CURRENT_DATE
   736→      AND NOT EXISTS (
   737→        SELECT 1 FROM date_series d2
   738→        WHERE d2.check_date > d.check_date
   739→        AND d2.check_date <= CURRENT_DATE
   740→        AND NOT EXISTS (
   741→          SELECT 1 FROM practice_sessions
   742→          WHERE user_id = $1 AND DATE(created_at) = d2.check_date
   743→        )
   744→      )`,
   745→      [req.user.id]
   746→    );
   747→
   748→    res.json({
   749→      success: true,
   750→      stats: {
   751→        total_questions: parseInt(stats.rows[0].total_questions) || 0,
   752→        average_score: parseFloat(stats.rows[0].average_score) || null,
   753→        improvement: improvementPercent,
   754→        day_streak: parseInt(streakResult.rows[0].streak) || 0,
   755→        last_practice: stats.rows[0].last_practice
   756→      }
   757→    });
   758→  } catch (err) {
   759→    console.error('Get practice stats error:', err);
   760→    res.status(500).json({ error: 'Failed to fetch statistics' });
   761→  }
   762→});
