  1851→// Voice response endpoint — candidate audio → Whisper transcription → AI response → TTS audio
  1852→router.post('/mock/:sessionId/voice-respond', authMiddleware, upload.single('audio'), async (req, res) => {
  1853→  try {
  1854→    const sessionId = req.params.sessionId;
  1855→
  1856→    // BUG FIX: Validate sessionId is a valid integer (prevents "undefined" SQL errors)
  1857→    if (!sessionId || sessionId === 'undefined' || sessionId === 'null' || isNaN(parseInt(sessionId))) {
  1858→      return res.status(400).json({ error: 'Invalid session. Please restart the interview.' });
  1859→    }
  1860→
  1861→    // Get session
  1862→    const sessionResult = await pool.query(
  1863→      'SELECT * FROM mock_interview_sessions WHERE id = $1 AND user_id = $2 AND status = $3',
  1864→      [parseInt(sessionId), req.user.id, 'in_progress']
  1865→    );
  1866→
  1867→    if (sessionResult.rows.length === 0) {
  1868→      return res.status(404).json({ error: 'Session not found or already completed' });
  1869→    }
  1870→
  1871→    const session = sessionResult.rows[0];
  1872→    const conversation = session.conversation || [];
  1873→    const questionIds = session.question_ids || [];
  1874→
  1875→    // Step 1: Transcribe audio with Whisper (with client-side SpeechRecognition fallback)
  1876→    // The client sends the live SpeechRecognition transcript alongside the audio as a fallback
  1877→    const clientTranscript = (req.body.response_text || '').trim();
  1878→    let transcribedText = '';
  1879→    let usedFallback = false;
  1880→
  1881→    if (req.file) {
  1882→      // Audio file uploaded as multipart — use ASR fallback chain (Whisper → NIM Parakeet v2 → v3)
  1883→      const baseMime = (req.file.mimetype || 'audio/webm').split(';')[0];
  1884→      const ext = baseMime.includes('mp4') ? 'mp4' : baseMime.includes('ogg') ? 'ogg' : 'webm';
  1885→      const filename = `recording.${ext}`;
  1886→      console.log(`[voice-respond] Received file: ${req.file.size} bytes, mime: ${req.file.mimetype}, client transcript: ${clientTranscript.length} chars`);
  1887→
  1888→      try {
  1889→        // Use the full ASR fallback chain (OpenAI Whisper → NIM Parakeet v2 → NIM Parakeet v3)
  1890→        const asrResult = await aiProvider.transcribeAudio(
  1891→          req.file.buffer,
  1892→          filename,
  1893→          baseMime,
  1894→          { subscriptionId: req.user.stripe_subscription_id, module: 'mock_interview', feature: 'voice_transcription' }
  1895→        );
  1896→        if (asrResult && asrResult.text) {
  1897→          transcribedText = asrResult.text.trim();
  1898→          console.log(`[voice-respond] ASR transcription: "${transcribedText.substring(0, 100)}..."`);
  1899→        } else if (clientTranscript.length >= 10) {
  1900→          // ASR returned nothing — use client transcript
  1901→          transcribedText = clientTranscript;
  1902→          usedFallback = true;
  1903→          console.log(`[voice-respond] ASR empty, using client transcript`);
  1904→        }
  1905→      } catch (asrErr) {
  1906→        console.error('[voice-respond] ASR fallback chain failed:', asrErr.message);
  1907→        // All ASR providers failed — fall back to client-side SpeechRecognition transcript
  1908→        if (clientTranscript.length >= 10) {
  1909→          transcribedText = clientTranscript;
  1910→          usedFallback = true;
  1911→          console.log(`[voice-respond] Using client SpeechRecognition fallback: "${transcribedText.substring(0, 100)}..."`);
  1912→        }
  1913→      }
  1914→    } else if (req.body.audio_base64) {
  1915→      const whisperResult = await transcribeAudioWithWhisper(req.body.audio_base64, {
  1916→        subscriptionId: req.user.stripe_subscription_id
  1917→      });
  1918→      if (whisperResult && whisperResult.text) {
  1919→        transcribedText = whisperResult.text.trim();
  1920→      }
  1921→    } else if (clientTranscript.length >= 5) {
  1922→      // Client-side transcript only (no audio file)
  1923→      transcribedText = clientTranscript;
  1924→      usedFallback = true;
  1925→    }
  1926→
  1927→    // BUG FIX: Whisper hallucinates known phrases on silent/near-silent audio
  1928→    const WHISPER_HALLUCINATIONS = [
  1929→      'ご視聴ありがとうございました', '視聴ありがとうございました', 'ありがとうございました',
  1930→      'ご視聴ありがとうございます', '字幕', 'サブスクライブ', 'チャンネル登録',
  1931→      '谢谢观看', '感谢观看', 'Sous-titres', 'Sottotitoli', 'Untertitel',
  1932→      'Thanks for watching', 'Thank you for watching', 'Please subscribe', 'Like and subscribe',
  1933→    ];
  1934→    const isHallucination = !usedFallback && WHISPER_HALLUCINATIONS.some(phrase =>
  1935→      transcribedText.toLowerCase().includes(phrase.toLowerCase())
  1936→    );
  1937→    if (isHallucination) {
  1938→      console.log(`[voice-respond] Filtered Whisper hallucination: "${transcribedText}"`);
  1939→      // Try client transcript before rejecting
  1940→      if (clientTranscript.length >= 10) {
  1941→        transcribedText = clientTranscript;
  1942→        usedFallback = true;
  1943→      } else {
  1944→        return res.status(400).json({ error: 'I didn\'t catch that. Could you please repeat your answer.' });
  1945→      }
