const Anthropic = require('@anthropic-ai/sdk');
const OpenAI = require('openai');
const fetch = require('node-fetch');
const FormData = require('form-data');

// AI Provider Fallback Service — auto-switches providers on failure
const aiProvider = require('./ai-provider');

const anthropic = new Anthropic({
  baseURL: process.env.POLSIA_API_URL || 'https://polsia.com/api/proxy/ai',
  apiKey: process.env.POLSIA_API_KEY,
});

// OpenAI client for vision tasks (Polsia AI proxy supports multimodal via OpenAI format)
const openai = new OpenAI(); // Uses OPENAI_BASE_URL and OPENAI_API_KEY from env

// Robust JSON parser — handles malformed LLM output (markdown fences, trailing commas, unescaped chars)
function safeParseJSON(text) {
  if (!text || typeof text !== 'string') return null;

  // Step 1: Strip markdown code fences
  let cleaned = text.replace(/```(?:json)?\s*/gi, '').replace(/```\s*/g, '');

  // Step 2: Extract the outermost JSON object or array
  const match = cleaned.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);
  if (!match) return null;
  cleaned = match[0];

  // Step 3: Try direct parse first
  try { return JSON.parse(cleaned); } catch (e) { /* continue to repair */ }

  // Step 4: Remove trailing commas before } or ]
  let repaired = cleaned.replace(/,\s*([}\]])/g, '$1');

  // Step 5: Strip control characters (except \n \r \t) within strings
  repaired = repaired.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');

  try { return JSON.parse(repaired); } catch (e) { /* continue */ }

  // Step 6: Fix unescaped newlines inside JSON strings (replace literal newlines with \n)
  repaired = repaired.replace(/"([^"]*?)"/g, (match, content) => {
    return '"' + content.replace(/\n/g, '\\n').replace(/\r/g, '\\r').replace(/\t/g, '\\t') + '"';
  });

  try { return JSON.parse(repaired); } catch (e) { /* continue */ }

  // Step 7: Last resort — try to fix common quote escaping issues
  // Replace curly/smart quotes with straight quotes
  repaired = repaired.replace(/[\u201C\u201D\u201E\u201F\u2033\u2036]/g, '"');
  repaired = repaired.replace(/[\u2018\u2019\u201A\u201B\u2032\u2035]/g, "'");

  try { return JSON.parse(repaired); } catch (e) {
    console.warn('[safeParseJSON] All repair attempts failed:', e.message);
    return null;
  }
}

// Upload a base64 image frame to R2 and return the CDN URL
// The Polsia OpenAI proxy only supports HTTP URLs for vision, NOT base64 data URIs
async function uploadFrameToR2(base64Data, index) {
  try {
    // Strip data URI prefix if present
    const raw = base64Data.replace(/^data:image\/\w+;base64,/, '');
    const buffer = Buffer.from(raw, 'base64');

    const formData = new FormData();
    formData.append('file', buffer, {
      filename: `video-frame-${Date.now()}-${index}.jpg`,
      contentType: 'image/jpeg'
    });

    const res = await fetch('https://polsia.com/api/proxy/r2/upload', {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${process.env.POLSIA_API_KEY}`,
        ...formData.getHeaders()
      },
      body: formData
    });

    // Scheduled interviews (recruiter-side)
    await client.query(`
      CREATE TABLE IF NOT EXISTS scheduled_interviews (
        id SERIAL PRIMARY KEY,
        company_id INTEGER REFERENCES companies(id) ON DELETE CASCADE,
        job_id INTEGER REFERENCES jobs(id) ON DELETE CASCADE,
        candidate_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        recruiter_id INTEGER REFERENCES users(id) ON DELETE SET NULL,
        scheduled_at TIMESTAMP NOT NULL,
        duration_minutes INTEGER DEFAULT 60,
        interview_type VARCHAR(50) DEFAULT 'video',
        meeting_link TEXT,
        notes TEXT,
        status VARCHAR(50) DEFAULT 'scheduled',
        outcome VARCHAR(50),
        feedback JSONB,
        created_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Job applications
    await client.query(`
      CREATE TABLE IF NOT EXISTS job_applications (
        id SERIAL PRIMARY KEY,
        job_id INTEGER REFERENCES jobs(id) ON DELETE CASCADE,
        candidate_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        company_id INTEGER REFERENCES companies(id) ON DELETE CASCADE,
        status VARCHAR(50) DEFAULT 'applied',
        resume_url TEXT,
        cover_letter TEXT,
        omniscore_at_apply INTEGER,
        recruiter_notes TEXT,
        applied_at TIMESTAMP DEFAULT NOW(),
        updated_at TIMESTAMP DEFAULT NOW(),
        UNIQUE(job_id, candidate_id)
      )
    `);

    // Add company_id to jobs table if not exists
    await client.query(`
      ALTER TABLE jobs ADD COLUMN IF NOT EXISTS company_id INTEGER REFERENCES companies(id) ON DELETE SET NULL
    `);

    // Add recruiter role fields to users
    await client.query(`
      ALTER TABLE users ADD COLUMN IF NOT EXISTS company_id INTEGER REFERENCES companies(id) ON DELETE SET NULL
    `);

    // Create indexes
    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_trust_score_company ON trust_scores(company_id);
      CREATE INDEX IF NOT EXISTS idx_trust_components_company ON trust_score_components(company_id);
      CREATE INDEX IF NOT EXISTS idx_job_analytics_job ON job_analytics(job_id);
      CREATE INDEX IF NOT EXISTS idx_candidate_feedback_company ON candidate_feedback(company_id);
      CREATE INDEX IF NOT EXISTS idx_scheduled_interviews_company ON scheduled_interviews(company_id);
      CREATE INDEX IF NOT EXISTS idx_scheduled_interviews_date ON scheduled_interviews(scheduled_at);
      CREATE INDEX IF NOT EXISTS idx_job_applications_job ON job_applications(job_id);
      CREATE INDEX IF NOT EXISTS idx_job_applications_candidate ON job_applications(candidate_id);
    `);

    console.log('TrustScore tables created successfully');
  }
};

