          </div>
          {interview.meeting_link && (
            <a href={interview.meeting_link} target="_blank" rel="noopener noreferrer">
              <Button size="lg">
                <Video className="h-4 w-4 mr-2" /> Join Call
              </Button>
            </a>
          )}
        </div>
      </CardContent>
    </Card>
  )
}

function InterviewCard({
